const items = $input.all();

const validExts = ['flac', 'm4a', 'mp3', 'mp4', 'mpeg', 'mpga', 'oga', 'ogg', 'wav', 'webm'];

for (const item of items) {
  const binaryKeys = Object.keys(item.binary || {});
  if (binaryKeys.length === 0) {
    throw new Error('Nenhum arquivo binário recebido no webhook. Verifique se o HTML está enviando o áudio como FormData.');
  }

  // Encontra o primeiro campo binário (geralmente 'audio')
  const fieldName = binaryKeys[0];
  const binData = item.binary[fieldName];

  // Normaliza extensão e mimeType para o Whisper aceitar
  let ext = (binData.fileName || '').split('.').pop().toLowerCase();
  if (!validExts.includes(ext)) ext = 'webm';

  binData.fileName = `audio.${ext}`;
  binData.fileExtension = ext;
  binData.mimeType = ext === 'mp3' ? 'audio/mpeg' 
    : ext === 'webm' ? 'audio/webm'
    : ext === 'ogg' || ext === 'oga' ? 'audio/ogg'
    : ext === 'm4a' || ext === 'mp4' ? 'audio/mp4'
    : ext === 'wav' ? 'audio/wav'
    : 'audio/webm';

  // Move o binário para 'data' (o Whisper node espera esse nome)
  if (fieldName !== 'data') {
    item.binary.data = binData;
    delete item.binary[fieldName];
  }

  // Captura metadados úteis do form
  item.json = {
    ...item.json,
    data_hora: new Date().toISOString(),
    extensao: ext
  };
}

return items;

