// Pega o texto completo (SOAP + avaliação)
const texto = $('Formatar Mensagem Final').item.json.mensagem_completa;

// Garante que termina com \n para inserção limpa
const fullText = texto.endsWith('\n') ? texto : texto + '\n';

// O Google Docs sempre começa no índice 1
// Vamos inserir todo o texto de uma vez, depois aplicar estilos por posição

const requests = [];

// 1. Inserir todo o texto no índice 1
requests.push({
  insertText: {
    location: { index: 1 },
    text: fullText
  }
});

// 2. Estilo base: fonte 10, preto, em todo o documento
requests.push({
  updateTextStyle: {
    range: { startIndex: 1, endIndex: fullText.length + 1 },
    textStyle: {
      fontSize: { magnitude: 10, unit: 'PT' },
      foregroundColor: { color: { rgbColor: { red: 0, green: 0, blue: 0 } } }
    },
    fields: 'fontSize,foregroundColor'
  }
});

// 3. Encontrar a linha de data/hora (primeira linha) e aplicar fonte 12 preto
const linhas = fullText.split('\n');
const primeiraLinha = linhas[0];
// Detecta se a primeira linha parece data/hora (contém / ou :)
if (/\d{2}\/\d{2}\/\d{4}/.test(primeiraLinha)) {
  requests.push({
    updateTextStyle: {
      range: { startIndex: 1, endIndex: primeiraLinha.length + 1 },
      textStyle: { fontSize: { magnitude: 12, unit: 'PT' } },
      fields: 'fontSize'
    }
  });
}

// 4. Encontrar cada "S:", "O:", "A:", "P:" no início de linha
//    e aplicar azul-marinho + fonte 12 nos 2 caracteres (letra + dois-pontos)
const azulMarinho = { red: 0, green: 0, blue: 0.5 };
let offset = 0; // posição corrente no texto (0-based)

for (const linha of linhas) {
  // Verifica se a linha começa com S: O: A: P: (maiúsculas, seguido de dois-pontos)
  const match = linha.match(/^([SOAP]):/);
  if (match) {
    // Posição no documento: offset + 1 (Docs é 1-based)
    const startIdx = offset + 1;
    const endIdx = startIdx + 2; // letra + ":"
    requests.push({
      updateTextStyle: {
        range: { startIndex: startIdx, endIndex: endIdx },
        textStyle: {
          fontSize: { magnitude: 12, unit: 'PT' },
          foregroundColor: { color: { rgbColor: azulMarinho } },
          bold: true
        },
        fields: 'fontSize,foregroundColor,bold'
      }
    });
  }
  // Avança o offset: comprimento da linha + 1 (o \n)
  offset += linha.length + 1;
}

return [{
  json: {
    requests: requests,
    titulo: 'Consulta_SOAP_Web_' + $now.toFormat('dd-MM-yyyy_HH-mm')
  }
}];

